#include <stdio.h>
#include <math.h>

define MIN(a, b) ((a) < (b) ? (a) : (b))

double euclidean_distance(double x[], double prototype[], int n) {
 double sum = 0;
 for (int i = 0; i < n; i++) {
 sum += pow(x[i] - prototype[i], 2);
 }
 return sqrt(sum);
}

int minimum_distance_classifier(double x[], double prototypes[][2], int c) {
 double min_distance = INFINITY;
 int assigned_class = -1;
 for (int i = 0; i < c; i++) {
 double distance = euclidean_distance(x, prototypes[i], 2);
 if (distance < min_distance) {
 min_distance = distance;
 assigned_class = i;
 }
 }
 return assigned_class;
}

int main() {
 double prototypes[][2] = {{1.67, 2.00}, {4.67, 4.67}};
 double x[] = {4, 3};
 int assigned_class = minimum_distance_classifier(x, prototypes, 2);
 printf("Assigned class: %d\n", assigned_class);
 return 0;
}
